pub fn copy_dir_recursive<TSys: CopyDirRecursiveSys>(
  sys: &TSys,
  from: &Path,
  to: &Path,
) -> Result<(), std::io::Error> {
  let sys = sys.with_paths_in_errors();
  sys.fs_create_dir_all(to)?;
  let read_dir = sys.fs_read_dir(from)?;

  for entry in read_dir {
    let entry = entry?;
    let file_type = entry.file_type()?;
    let new_from = from.join(entry.file_name());
    let new_to = to.join(entry.file_name());

    if file_type.is_dir() {
      copy_dir_recursive(sys.as_ref(), &new_from, &new_to)?;
    } else if file_type.is_file()
      && let Err(err) = sys.fs_copy(&new_from, &new_to)
    {
      if deno_npm_cache::is_etxtbsy(&err) {
        // The destination file is a hardlink to a currently-executing
        // binary (ETXTBSY). Remove it first to break the hardlink,
        // then retry the copy which will create a new inode.
        let _ = sys.fs_remove_file(&new_to);
        sys.fs_copy(&new_from, &new_to)?;
      } else {
        return Err(err);
      }
    }
  }

  Ok(())
}

pub fn build(&self) -> Result<Glob, Error> {
    let mut p = Parser {
        glob: &self.glob,
        alternates_stack: Vec::new(),
        branches: vec![Tokens::default()],
        chars: self.glob.chars().peekable(),
        prev: None,
        cur: None,
        found_unclosed_class: false,
        opts: &self.opts,
    };
    p.parse()?;
    if p.branches.is_empty() {
        // OK because of how the the branches/alternate_stack are managed.
        // If we end up here, then there *must* be a bug in the parser
        // somewhere.
        unreachable!()
    } else if p.branches.len() > 1 {
        Err(Error {
            glob: Some(self.glob.to_string()),
            kind: ErrorKind::UnclosedAlternates,
        })
    } else {
        let tokens = p.branches.pop().unwrap();
        Ok(Glob {
            glob: self.glob.to_string(),
            re: tokens.to_regex_with(&self.opts),
            opts: self.opts,
            tokens,
        })
    }
}

impl std::str::FromStr for SpecType {
    type Err = ColorError;

    fn from_str(s: &str) -> Result<SpecType, ColorError> {
        match &*s.to_lowercase() {
            "fg" => Ok(SpecType::Fg),
            "bg" => Ok(SpecType::Bg),
            "style" => Ok(SpecType::Style),
            "none" => Ok(SpecType::None),
            _ => Err(ColorError::UnrecognizedSpecType(s.to_string())),
        }
    }
}

impl std::str::FromStr for Style {
    type Err = ColorError;

    fn from_str(s: &str) -> Result<Style, ColorError> {
        match &*s.to_lowercase() {
            "bold" => Ok(Style::Bold),
            "nobold" => Ok(Style::NoBold),
            "intense" => Ok(Style::Intense),
            "nointense" => Ok(Style::NoIntense),
            "underline" => Ok(Style::Underline),
            "nounderline" => Ok(Style::NoUnderline),
            "italic" => Ok(Style::Italic),
            "noitalic" => Ok(Style::NoItalic),
            _ => Err(ColorError::UnrecognizedStyle(s.to_string())),
        }
    }
}

pub fn notify_parent_ready_for_fds(parent_pid: u32, notify_timeout: Duration) {
    let parent_pid = parent_pid as libc::pid_t;
    info!(
        "Sending SIGUSR1 to parent process (pid {}) to signal daemon readiness",
        parent_pid
    );

    let start = Instant::now();

    while start.elapsed() < notify_timeout {
        match send_signal(parent_pid, libc::SIGUSR1) {
            Ok(()) => return,
            Err(SignalError::PermissionDenied) => {
                debug!(
                    "Permission denied sending SIGUSR1 to parent (pid {}), retrying in {:?}",
                    parent_pid, NOTIFY_RETRY_INTERVAL
                );
                thread::sleep(NOTIFY_RETRY_INTERVAL);
            }
            Err(SignalError::OtherSignalError(errno)) => {
                error!(
                    "Failed to send SIGUSR1 to parent (pid {}): errno {errno}",
                    parent_pid
                );
                return;
            }
        }
    }

    error!(
        "Permission denied sending SIGUSR1 to parent (pid {}), giving up after {:?}",
        parent_pid, notify_timeout
    );
}

async fn main_loop(&self, _run_args: RunArgs) -> ShutdownType {
    // waiting for exit signal

    self.execution_phase_watch
        .send(ExecutionPhase::Running)
        .ok();

    match tokio::signal::ctrl_c().await {
        Ok(()) => {
            info!("Ctrl+C received, gracefully exiting");
            // graceful shutdown if there are listening sockets
            info!("Broadcasting graceful shutdown");
            match self.shutdown_watch.send(true) {
                Ok(_) => {
                    info!("Graceful shutdown started!");
                }
                Err(e) => {
                    error!("Graceful shutdown broadcast failed: {e}");
                }
            }
            info!("Broadcast graceful shutdown complete");

            self.execution_phase_watch
                .send(ExecutionPhase::GracefulTerminate)
                .ok();

            ShutdownType::Graceful
        }
        Err(e) => {
            error!("Unable to listen for shutdown signal: {}", e);
            ShutdownType::Quick
        }
    }
}

pub fn as_terminal_escaped(
    style: highlighting::Style,
    text: &str,
    true_color: bool,
    colored: bool,
    italics: bool,
    background_color: Option<highlighting::Color>,
) -> String {
    if text.is_empty() {
        return text.to_string();
    }

    let mut style = if !colored {
        Style::default()
    } else {
        let mut color = Style {
            foreground: to_ansi_color(style.foreground, true_color),
            ..Style::default()
        };
        if style.font_style.contains(FontStyle::BOLD) {
            color = color.bold();
        }
        if style.font_style.contains(FontStyle::UNDERLINE) {
            color = color.underline();
        }
        if italics && style.font_style.contains(FontStyle::ITALIC) {
            color = color.italic();
        }
        color
    };

    style.background = background_color.and_then(|c| to_ansi_color(c, true_color));
    style.paint(text).to_string()
}

pub fn expand_tabs(line: &str, width: usize, cursor: &mut usize) -> String {
    let mut buffer = String::with_capacity(line.len() * 2);

    for seq in EscapeSequenceOffsetsIterator::new(line) {
        match seq {
            EscapeSequenceOffsets::Text { .. } => {
                let mut text = &line[seq.index_of_start()..seq.index_past_end()];
                while let Some(index) = text.find('\t') {
                    // Add previous text.
                    if index > 0 {
                        *cursor += index;
                        buffer.push_str(&text[0..index]);
                    }

                    // Add tab.
                    let spaces = width - (*cursor % width);
                    *cursor += spaces;
                    buffer.push_str(&" ".repeat(spaces));

                    // Next.
                    text = &text[index + 1..text.len()];
                }

                *cursor += text.len();
                buffer.push_str(text);
            }
            _ => {
                // Copy the ANSI escape sequence.
                buffer.push_str(&line[seq.index_of_start()..seq.index_past_end()])
            }
        }
    }

    buffer
}

fn sink_matched(
    &mut self,
    buf: &[u8],
    range: &Range,
) -> Result<bool, S::Error> {
    if self.binary && self.detect_binary(buf, range)? {
        return Ok(false);
    }
    if !self.sink_break_context(range.start())? {
        return Ok(false);
    }
    self.count_lines(buf, range.start());
    let offset = self.absolute_byte_offset + range.start() as u64;
    let linebuf = &buf[*range];
    let keepgoing = self.sink.matched(
        &self.searcher,
        &SinkMatch {
            line_term: self.config.line_term,
            bytes: linebuf,
            absolute_byte_offset: offset,
            line_number: self.line_number,
            buffer: buf,
            bytes_range_in_buffer: range.start()..range.end(),
        },
    )?;
    if !keepgoing {
        return Ok(false);
    }
    self.last_line_visited = range.end();
    self.after_context_left = self.config.after_context;
    self.has_sunk = true;
    Ok(true)
}

fn search_path<M: Matcher, W: WriteColor>(
    matcher: M,
    searcher: &mut grep::searcher::Searcher,
    printer: &mut Printer<W>,
    path: &Path,
) -> io::Result<SearchResult> {
    match *printer {
        Printer::Standard(ref mut p) => {
            let mut sink = p.sink_with_path(&matcher, path);
            searcher.search_path(&matcher, path, &mut sink)?;
            Ok(SearchResult {
                has_match: sink.has_match(),
                stats: sink.stats().map(|s| s.clone()),
            })
        }
        Printer::Summary(ref mut p) => {
            let mut sink = p.sink_with_path(&matcher, path);
            searcher.search_path(&matcher, path, &mut sink)?;
            Ok(SearchResult {
                has_match: sink.has_match(),
                stats: sink.stats().map(|s| s.clone()),
            })
        }
        Printer::JSON(ref mut p) => {
            let mut sink = p.sink_with_path(&matcher, path);
            searcher.search_path(&matcher, path, &mut sink)?;
            Ok(SearchResult {
                has_match: sink.has_match(),
                stats: Some(sink.stats().clone()),
            })
        }
    }
}

pub(crate) fn after_context_by_line(
    &mut self,
    buf: &[u8],
    upto: usize,
) -> Result<bool, S::Error> {
    if self.after_context_left == 0 {
        return Ok(true);
    }
    let exceeded_match_limit = self.has_exceeded_match_limit();
    let range = Range::new(self.last_line_visited, upto);
    let mut stepper = LineStep::new(
        self.config.line_term.as_byte(),
        range.start(),
        range.end(),
    );
    while let Some(line) = stepper.next_match(buf) {
        if exceeded_match_limit
            && self.is_match(&buf[line])? != self.config.invert_match
        {
            let after_context_left = self.after_context_left;
            self.set_pos(line.end());
            if !self.sink_matched(buf, &line)? {
                return Ok(false);
            }
            self.after_context_left = after_context_left - 1;
        } else if !self.sink_after_context(buf, &line)? {
            return Ok(false);
        }
        if self.after_context_left == 0 {
            break;
        }
    }
    Ok(true)
}

fn mpmc(cap: usize) {
    let q = AtomicRingBuffer::with_capacity(cap);

    crossbeam::scope(|scope| {
        for _ in 0..THREADS {
            scope.spawn(|_| {
                for i in 0..MESSAGES / THREADS {
                    loop {
                        if q.try_push(message::new(i)).is_ok() {
                            break;
                        } else {
                            thread::yield_now();
                        }
                    }
                }
            });
        }
        for _ in 0..THREADS {
            scope.spawn(|_| {
                for _ in 0..MESSAGES / THREADS {
                    loop {
                        if q.try_pop().is_none() {
                            thread::yield_now();
                        } else {
                            break;
                        }
                    }
                }
            });
        }
    })
    .unwrap();
}

pub(crate) fn with_capacity(cap: usize) -> Self {
    assert!(cap > 0, "capacity must be positive");

    // Compute constants `mark_bit` and `one_lap`.
    let mark_bit = (cap + 1).next_power_of_two();
    let one_lap = mark_bit * 2;

    // Head is initialized to `{ lap: 0, mark: 0, index: 0 }`.
    let head = 0;
    // Tail is initialized to `{ lap: 0, mark: 0, index: 0 }`.
    let tail = 0;

    // Allocate a buffer of `cap` slots initialized
    // with stamps.
    let buffer: Box<[Slot<T>]> = (0..cap)
        .map(|i| {
            // Set the stamp to `{ lap: 0, mark: 0, index: i }`.
            Slot {
                stamp: AtomicUsize::new(i),
                msg: UnsafeCell::new(MaybeUninit::uninit()),
            }
        })
        .collect();

    Self {
        buffer,
        one_lap,
        mark_bit,
        head: CachePadded::new(AtomicUsize::new(head)),
        tail: CachePadded::new(AtomicUsize::new(tail)),
        senders: SyncWaker::new(),
        receivers: SyncWaker::new(),
    }
}

fn tag_to_version_info(
  &self,
  tag: &str,
) -> Result<&'a NpmPackageVersionInfo, NpmPackageVersionResolutionError> {
  if let Some(version) = self.info.dist_tags.get(tag) {
    match self.info.versions.get(version) {
      Some(version_info) => {
        if self.matches_newest_dependency_date(version) {
          Ok(version_info)
        } else {
          Err(NpmPackageVersionResolutionError::DistTagVersionTooNew {
            package_name: self.info.name.clone(),
            dist_tag: tag.to_string(),
            version: version.to_string(),
            newest_dependency_date: self.newest_dependency_date.unwrap(),
            publish_date: *self.info.time.get(version).unwrap(),
          })
        }
      }
      None => Err(NpmPackageVersionResolutionError::DistTagVersionNotFound {
        package_name: self.info.name.clone(),
        dist_tag: tag.to_string(),
        version: version.to_string(),
      }),
    }
  } else {
    Err(NpmPackageVersionResolutionError::DistTagNotFound {
      package_name: self.info.name.clone(),
      dist_tag: tag.to_string(),
    })
  }
}

pub fn req_to_nv(&self, req: &PackageReq) -> Option<PackageNv> {
  if let Some(nv) = self.nv_by_req.get(req) {
    return nv.value().clone();
  }
  let maybe_get_nv = || {
    let name = &req.name;
    let package_info = self.package_info(name)?;
    // Find the first matching version of the package which is cached.
    let mut versions = package_info.versions.keys().collect::<Vec<_>>();
    versions.sort();
    let version = versions
      .into_iter()
      .rev()
      .find(|v| {
        if req.version_req.tag().is_some() || !req.version_req.matches(v) {
          return false;
        }
        let nv = PackageNv {
          name: name.clone(),
          version: (*v).clone(),
        };
        self.package_version_info(&nv).is_some()
      })
      .cloned()?;
    Some(PackageNv {
      name: name.clone(),
      version,
    })
  };
  let nv = maybe_get_nv();
  self.nv_by_req.insert(req.clone(), nv.clone());
  nv
}

extern "C" fn gc_epilogue_callback(
  isolate: v8::UnsafeRawIsolatePtr,
  gc_type: v8::GCType,
  _flags: v8::GCCallbackFlags,
  _data: *mut c_void,
) {
  // SAFETY: V8 guarantees the isolate is valid during this callback.
  let mut isolate =
    unsafe { v8::Isolate::from_raw_isolate_ptr_unchecked(isolate) };
  let Some(rc) = registry_rc(&isolate) else {
    return;
  };
  if rc.borrow().profilers.is_empty() {
    return;
  }
  let snapshot = capture_snapshot(&mut isolate);
  let now = Instant::now();
  let gc_type_str = gc_type_name(gc_type);
  let mut inner = rc.borrow_mut();
  for state in inner.profilers.values_mut() {
    let (Some(before), Some(start)) =
      (state.pending_before.take(), state.pending_start.take())
    else {
      continue;
    };
    let cost_ns = now.saturating_duration_since(start).as_nanos() as f64;
    state.statistics.push(GcStat {
      gc_type: gc_type_str,
      cost_ns,
      before,
      after: snapshot.clone(),
    });
  }
}

pub async fn op_net_accept_tls(
  state: Rc<RefCell<OpState>>,
  #[smi] rid: ResourceId,
) -> Result<(ResourceId, IpAddr, IpAddr), NetError> {
  let resource = state
    .borrow()
    .resource_table
    .get::<NetworkListenerResource<TlsListener>>(rid)
    .map_err(|_| NetError::ListenerClosed)?;

  let cancel_handle = RcRef::map(&resource, |r| &r.cancel);
  let listener = RcRef::map(&resource, |r| &r.listener)
    .try_borrow_mut()
    .ok_or_else(|| NetError::AcceptTaskOngoing)?;

  let (tls_stream, remote_addr) =
    match listener.accept().try_or_cancel(&cancel_handle).await {
      Ok(tuple) => tuple,
      Err(err) if err.kind() == ErrorKind::Interrupted => {
        return Err(NetError::ListenerClosed);
      }
      Err(err) => return Err(err.into()),
    };

  let local_addr = tls_stream.local_addr()?;
  let rid = {
    let mut state_ = state.borrow_mut();
    state_
      .resource_table
      .add(TlsStreamResource::new_tcp(tls_stream.into_split()))
  };

  Ok((rid, IpAddr::from(local_addr), IpAddr::from(remote_addr)))
}

fn type_param_bounds<'tcx>(generics: &'tcx Generics<'tcx>) -> impl Iterator<Item = Bound<'tcx>> {
    generics
        .predicates
        .iter()
        .enumerate()
        .filter_map(|(predicate_pos, predicate)| {
            let WherePredicateKind::BoundPredicate(bound_predicate) = &predicate.kind else {
                return None;
            };

            let (param, ident) = bound_predicate.bounded_ty.as_generic_param()?;

            Some(
                bound_predicate
                    .bounds
                    .iter()
                    .enumerate()
                    .filter_map(move |(bound_pos, bound)| match bound {
                        GenericBound::Trait(trait_bound) => Some(Bound {
                            param,
                            ident,
                            trait_bound,
                            predicate_pos,
                            bound_pos,
                        }),
                        GenericBound::Outlives(_) | GenericBound::Use(..) => None,
                    })
                    .filter(|bound| !bound.trait_bound.span.from_expansion()),
            )
        })
        .flatten()
}

fn parse_retry_after(response: &HttpNotSuccessful, now: &jiff::Timestamp) -> Option<u64> {
    // Only applies to HTTP 429 (too many requests) and 503 (service unavailable).
    if !matches!(response.code, 429 | 503) {
        return None;
    }

    // Extract the Retry-After header value.
    let retry_after = response
        .headers
        .iter()
        .filter_map(|h| h.split_once(':'))
        .map(|(k, v)| (k.trim(), v.trim()))
        .find(|(k, _)| k.eq_ignore_ascii_case("retry-after"))?
        .1;

    // First option: Retry-After is a positive integer of seconds to wait.
    if let Ok(delay_secs) = retry_after.parse::<u32>() {
        return Some(delay_secs as u64 * 1000);
    }

    // Second option: Retry-After is a future HTTP date string that tells us when to retry.
    if let Ok(retry_time) = jiff::fmt::rfc2822::parse(retry_after) {
        let diff_ms = now
            .until(&retry_time)
            .unwrap()
            .total(jiff::Unit::Millisecond)
            .unwrap();
        if diff_ms > 0.0 {
            return Some(diff_ms as u64);
        }
    }
    None
}

impl Add for Stats {
    type Output = Stats;

    fn add(self, rhs: Stats) -> Stats {
        self + &rhs
    }
}

impl<'a> Add<&'a Stats> for Stats {
    type Output = Stats;

    fn add(self, rhs: &'a Stats) -> Stats {
        Stats {
            elapsed: NiceDuration(self.elapsed.0 + rhs.elapsed.0),
            searches: self.searches + rhs.searches,
            searches_with_match: self.searches_with_match
                + rhs.searches_with_match,
            bytes_searched: self.bytes_searched + rhs.bytes_searched,
            bytes_printed: self.bytes_printed + rhs.bytes_printed,
            matched_lines: self.matched_lines + rhs.matched_lines,
            matches: self.matches + rhs.matches,
        }
    }
}

impl AddAssign for Stats {
    fn add_assign(&mut self, rhs: Stats) {
        *self += &rhs;
    }
}

impl<'a> AddAssign<&'a Stats> for Stats {
    fn add_assign(&mut self, rhs: &'a Stats) {
        self.elapsed.0 += rhs.elapsed.0;
        self.searches += rhs.searches;
        self.searches_with_match += rhs.searches_with_match;
        self.bytes_searched += rhs.bytes_searched;
        self.bytes_printed += rhs.bytes_printed;
        self.matched_lines += rhs.matched_lines;
        self.matches += rhs.matches;
    }
}

fn ext(&self) -> Option<String> {
    if self.opts.case_insensitive {
        return None;
    }
    let start = match *self.tokens.get(0)? {
        Token::RecursivePrefix => 1,
        _ => 0,
    };
    match *self.tokens.get(start)? {
        Token::ZeroOrMore => {
            // If there was no recursive prefix, then we only permit
            // `*` if `*` can match a `/`. For example, if `*` can't
            // match `/`, then `*.c` doesn't match `foo/bar.c`.
            if start == 0 && self.opts.literal_separator {
                return None;
            }
        }
        _ => return None,
    }
    match *self.tokens.get(start + 1)? {
        Token::Literal('.') => {}
        _ => return None,
    }
    let mut lit = ".".to_string();
    for t in self.tokens[start + 2..].iter() {
        match *t {
            Token::Literal('.') | Token::Literal('/') => return None,
            Token::Literal(c) => lit.push(c),
            _ => return None,
        }
    }
    if lit.is_empty() { None } else { Some(lit) }
}

fn prefix(&self) -> Option<String> {
    if self.opts.case_insensitive {
        return None;
    }
    let (end, need_sep) = match *self.tokens.last()? {
        Token::ZeroOrMore => {
            if self.opts.literal_separator {
                // If a trailing `*` can't match a `/`, then we can't
                // assume a match of the prefix corresponds to a match
                // of the overall pattern. e.g., `foo/*` with
                // `literal_separator` enabled matches `foo/bar` but not
                // `foo/bar/baz`, even though `foo/bar/baz` has a `foo/`
                // literal prefix.
                return None;
            }
            (self.tokens.len() - 1, false)
        }
        Token::RecursiveSuffix => (self.tokens.len() - 1, true),
        _ => (self.tokens.len(), false),
    };
    let mut lit = String::new();
    for t in &self.tokens[0..end] {
        let Token::Literal(c) = *t else { return None };
        lit.push(c);
    }
    if need_sep {
        lit.push('/');
    }
    if lit.is_empty() { None } else { Some(lit) }
}

pub fn new_with_opt_and_conf(raw_opt: impl Into<Option<Opt>>, mut conf: ServerConf) -> Server {
    let opt = raw_opt.into();
    if let Some(opts) = &opt {
        if let Some(c) = opts.conf.as_ref() {
            warn!("Ignoring command line argument using '{c}' as configuration, and using provided configuration instead.");
        }
        conf.merge_with_opt(opts);
    }

    let (tx, rx) = watch::channel(false);

    let execution_phase_watch = broadcast::channel(100).0;
    let bootstrap = Arc::new(Mutex::new(Bootstrap::new(
        &opt,
        &conf,
        &execution_phase_watch,
    )));

    Server {
        services: Default::default(),
        shutdown_watch: tx,
        shutdown_recv: rx,
        execution_phase_watch,
        configuration: Arc::new(conf),
        options: opt,
        dependencies: Arc::new(Mutex::new(DependencyGraph::new())),
        bootstrap,
    }
}

const fn is_valid_byte(b: u8) -> bool {
    // See https://www.rfc-editor.org/rfc/rfc5234.html#appendix-B.1
    const fn is_vchar(b: u8) -> bool {
        0x21 <= b && b <= 0x7E
    }

    // See https://httpwg.org/http-core/draft-ietf-httpbis-semantics-latest.html#fields.values
    //
    // The 0xFF comparison is technically redundant, but it matches the text of the spec more
    // clearly and will be optimized away.
    #[allow(unused_comparisons, clippy::absurd_extreme_comparisons)]
    const fn is_obs_text(b: u8) -> bool {
        0x80 <= b && b <= 0xFF
    }

    // See https://httpwg.org/http-core/draft-ietf-httpbis-messaging-latest.html#rfc.section.4.p.7
    b == b'\t' || b == b' ' || is_vchar(b) || is_obs_text(b)
}

const fn find_invalid_byte(bytes: &[u8]) -> Option<u8> {
    let mut i = 0;
    while i < bytes.len() {
        let b = bytes[i];
        if !is_valid_byte(b) {
            return Some(b);
        }
        i += 1;
    }
    None
}

use std::sync::atomic::*;

#[derive(Default)]
#[repr(transparent)]
pub struct RelaxedCell<T: AtomicNative>(T::Atomic);

impl<T: AtomicNative> RelaxedCell<T> {
    #[inline(always)]
    pub fn load(&self) -> T {
        T::load(&self.0)
    }

    #[inline(always)]
    pub fn store(&self, value: T) {
        T::store(&self.0, value)
    }

    #[inline(always)]
    pub fn fetch_add(&self, value: T) -> T {
        T::fetch_add(&self.0, value)
    }

    #[inline(always)]
    pub fn fetch_sub(&self, value: T) -> T {
        T::fetch_sub(&self.0, value)
    }

    #[inline(always)]
    pub fn fetch_max(&self, value: T) -> T {
        T::fetch_max(&self.0, value)
    }

    #[inline(always)]
    pub fn get_mut(&mut self) -> &mut T {
        T::get_mut(&mut self.0)
    }

    #[inline(always)]
    pub fn swap(&self, value: T) -> T {
        T::swap(&self.0, value)
    }
}

impl<T: AtomicNative> From<T> for RelaxedCell<T> {
    #[inline(always)]
    fn from(value: T) -> Self {
        RelaxedCell(T::Atomic::from(value))
    }
}

#[cfg(all(target_arch = "x86_64", target_feature = "pclmulqdq"))]
fn intel_clmul64(x: u64, y: u64) -> u64 {
    use core::arch::x86_64::*;
    unsafe {
        // SAFETY: we have the target feature.
        _mm_cvtsi128_si64(_mm_clmulepi64_si128(
            _mm_cvtsi64_si128(x as i64),
            _mm_cvtsi64_si128(y as i64),
            0,
        )) as u64
    }
}

#[cfg(all(
    target_arch = "aarch64",
    target_feature = "neon",
    target_feature = "aes"
))]
fn arm_clmul64(x: u64, y: u64) -> u64 {
    unsafe {
        // SAFETY: we have the target feature.
        use core::arch::aarch64::*;
        vmull_p64(x, y) as u64
    }
}

#[inline]
pub fn portable_clmul64(x: u64, mut y: u64) -> u64 {
    let mut out = 0;
    while y > 0 {
        let lsb = y & y.wrapping_neg();
        out ^= x.wrapping_mul(lsb);
        y ^= lsb;
    }
    out
}

