fn wait_or_kill_process(
    process: &mut Child,
    cmd: &str,
    duration: Duration,
    preserve_status: bool,
    foreground: bool,
    verbose: bool,
) -> std::io::Result<i32> {
    // ignore `SIGTERM` here
    match process.wait_or_timeout(duration, None) {
        Ok(Some(status)) => {
            if preserve_status {
                let exit_code = status.code().unwrap_or_else(|| {
                    status.signal().unwrap_or_else(|| {
                        // Extremely rare: process exited but we have neither exit code nor signal.
                        // This can happen on some platforms or in unusual termination scenarios.
                        ExitStatus::TimeoutFailed.into()
                    })
                });
                Ok(exit_code)
            } else {
                Ok(ExitStatus::CommandTimedOut.into())
            }
        }
        Ok(None) => {
            let signal = signal_by_name_or_value("KILL").unwrap();
            report_if_verbose(signal, cmd, verbose);
            send_signal(process, signal, foreground);
            process.wait()?;
            Ok(ExitStatus::SignalSent(signal).into())
        }
        Err(_) => Ok(ExitStatus::CommandTimedOut.into()),
    }
}

async fn non_multipart_form_data() {
    #[derive(MultipartForm)]
    struct TestNonMultipartFormData {
        #[allow(unused)]
        #[multipart(limit = "30B")]
        foo: Text<String>,
    }

    async fn non_multipart_form_data_route(
        _form: MultipartForm<TestNonMultipartFormData>,
    ) -> String {
        unreachable!("request is sent with multipart/mixed");
    }

    let srv = actix_test::start(|| {
        App::new().route("/", web::post().to(non_multipart_form_data_route))
    });

    let mut form = multipart::Form::default();
    form.add_text("foo", "foo");

    // mangle content-type, keeping the boundary
    let ct = form.content_type().replacen("/form-data", "/mixed", 1);

    let res = Client::default()
        .post(srv.url("/"))
        .content_type(ct)
        .send_body(multipart::Body::from(form))
        .await
        .unwrap();

    assert_eq!(res.status(), StatusCode::UNSUPPORTED_MEDIA_TYPE);
}

async fn test_middleware_app_data() {
    let srv = init_service(
        App::new().service(
            web::resource("test")
                .app_data(1usize)
                .wrap_fn(|req, srv| {
                    assert_eq!(req.app_data::<usize>(), Some(&1usize));
                    req.extensions_mut().insert(1usize);
                    srv.call(req)
                })
                .route(web::get().to(HttpResponse::Ok))
                .default_service(|req: ServiceRequest| async move {
                    let (req, _) = req.into_parts();

                    assert_eq!(req.extensions().get::<usize>(), Some(&1));

                    Ok(ServiceResponse::new(
                        req,
                        HttpResponse::BadRequest().finish(),
                    ))
                }),
        ),
    )
    .await;

    let req = TestRequest::get().uri("/test").to_request();
    let resp = call_service(&srv, req).await;
    assert_eq!(resp.status(), StatusCode::OK);

    let req = TestRequest::post().uri("/test").to_request();
    let resp = call_service(&srv, req).await;
    assert_eq!(resp.status(), StatusCode::BAD_REQUEST);
}

pub(crate) fn supported(&self) -> anyhow::Result<()> {
    match self.kind {
        SortModeKind::Path => Ok(()),
        SortModeKind::LastModified => {
            let md = std::env::current_exe()
                .and_then(|p| p.metadata())
                .and_then(|md| md.modified());
            let Err(err) = md else { return Ok(()) };
            anyhow::bail!(
                "sorting by last modified isn't supported: {err}"
            );
        }
        SortModeKind::LastAccessed => {
            let md = std::env::current_exe()
                .and_then(|p| p.metadata())
                .and_then(|md| md.accessed());
            let Err(err) = md else { return Ok(()) };
            anyhow::bail!(
                "sorting by last accessed isn't supported: {err}"
            );
        }
        SortModeKind::Created => {
            let md = std::env::current_exe()
                .and_then(|p| p.metadata())
                .and_then(|md| md.created());
            let Err(err) = md else { return Ok(()) };
            anyhow::bail!(
                "sorting by creation time isn't supported: {err}"
            );
        }
    }
}

pub(crate) fn derive_args(input: &DeriveInput) -> Result<TokenStream, syn::Error> {
    let ident = &input.ident;

    match input.data {
        Data::Struct(DataStruct {
            fields: Fields::Named(ref fields),
            ..
        }) => {
            let name = Name::Derived(ident.clone());
            let item = Item::from_args_struct(input, name)?;
            let fields = collect_args_fields(&item, fields)?;
            gen_for_struct(&item, ident, &input.generics, &fields)
        }
        Data::Struct(DataStruct {
            fields: Fields::Unit,
            ..
        }) => {
            let name = Name::Derived(ident.clone());
            let item = Item::from_args_struct(input, name)?;
            let fields = Punctuated::<Field, Comma>::new();
            let fields = fields
                .iter()
                .map(|field| {
                    let item = Item::from_args_field(field, item.casing(), item.env_casing())?;
                    Ok((field, item))
                })
                .collect::<Result<Vec<_>, syn::Error>>()?;
            gen_for_struct(&item, ident, &input.generics, &fields)
        }
        _ => abort_call_site!("`#[derive(Args)]` only supports non-tuple structs"),
    }
}

pub fn error_if_changed(&self) -> Result<(), JsErrorBox> {
  if !self.frozen {
    return Ok(());
  }
  let lockfile = self.lockfile.lock();
  if lockfile.has_content_changed {
    let contents = self
      .sys
      .fs_read_to_string(&lockfile.filename)
      .unwrap_or_default();
    let new_contents = lockfile.as_json_string();
    let diff = crate::display::diff(&contents, &new_contents);
    // has an extra newline at the end
    let diff = diff.trim_end();
    const MAX_DIFF_LINES: usize = 50;
    let truncated_diff = {
      let lines: Vec<&str> = diff.lines().collect();
      if lines.len() > MAX_DIFF_LINES {
        let shown: String = lines[..MAX_DIFF_LINES].join("\n");
        let remaining = lines.len() - MAX_DIFF_LINES;
        format!("{shown}\n... {remaining} more lines omitted ...")
      } else {
        diff.to_string()
      }
    };
    Err(JsErrorBox::generic(format!(
      "The lockfile is out of date. Run `deno install --frozen=false`, or rerun with `--frozen=false` to update it.\nchanges:\n{truncated_diff}"
    )))
  } else {
    Ok(())
  }
}

async fn insert_cache_asset(
  db: Arc<Mutex<Connection>>,
  put: CachePutRequest,
  response_body_key: Option<String>,
) -> Result<Option<String>, CacheError> {
  spawn_blocking(move || {
    let maybe_response_body = {
      let db = db.lock();
      db.query_row(
        "INSERT OR REPLACE INTO request_response_list
             (cache_id, request_url, request_headers, response_headers,
              response_body_key, response_status, response_status_text, last_inserted_at)
             VALUES (?1, ?2, ?3, ?4, ?5, ?6, ?7, ?8)
             RETURNING response_body_key",
        (
          put.cache_id,
          put.request_url,
          serialize_headers(&put.request_headers),
          serialize_headers(&put.response_headers),
          response_body_key,
          put.response_status,
          put.response_status_text,
          SystemTime::now().duration_since(UNIX_EPOCH).expect("SystemTime is before unix epoch").as_secs(),
        ),
        |row| {
          let response_body_key: Option<String> = row.get(0)?;
          Ok(response_body_key)
        },
      )?
    };
    Ok::<Option<String>, CacheError>(maybe_response_body)
  }).await?
}

fn git_ignore_tree() {
  let sys = InMemorySys::default();
  sys.fs_create_dir_all("/sub_dir/sub_dir").unwrap();
  sys.fs_write("/.gitignore", "file.txt").unwrap();
  sys.fs_write("/sub_dir/.gitignore", "data.txt").unwrap();
  sys
    .fs_write("/sub_dir/sub_dir/.gitignore", "!file.txt\nignore.txt")
    .unwrap();
  let mut ignore_tree = GitIgnoreTree::new(&sys, Vec::new());
  let mut run_test = |path: &str, expected: bool| {
    let path = PathBuf::from(path);
    let gitignore =
      ignore_tree.get_resolved_git_ignore_for_file(&path).unwrap();
    assert_eq!(
      gitignore.is_ignored(&path, /* is_dir */ false),
      expected,
      "Path: {}",
      path.display()
    );
  };
  run_test("/file.txt", true);
  run_test("/other.txt", false);
  run_test("/data.txt", false);
  run_test("/sub_dir/file.txt", true);
  run_test("/sub_dir/other.txt", false);
  run_test("/sub_dir/data.txt", true);
  run_test("/sub_dir/sub_dir/file.txt", false); // unignored up here
  run_test("/sub_dir/sub_dir/sub_dir/file.txt", false);
  run_test("/sub_dir/sub_dir/sub_dir/ignore.txt", true);
  run_test("/sub_dir/sub_dir/ignore.txt", true);
  run_test("/sub_dir/ignore.txt", false);
  run_test("/ignore.txt", false);
}

pub unsafe fn uv_stream_set_blocking(
  stream: *mut uv_stream_t,
  blocking: c_int,
) -> c_int {
  unsafe {
    let fd = if (*stream).r#type == uv_handle_type::UV_TTY {
      (*(stream as *mut uv_tty_t)).internal_fd
    } else {
      // TCP and other stream types
      match (*(stream as *mut uv_tcp_t)).internal_fd {
        Some(fd) => fd,
        None => return super::UV_EBADF,
      }
    };

    let flags = libc::fcntl(fd, libc::F_GETFL);
    if flags == -1 {
      return -(std::io::Error::last_os_error()
        .raw_os_error()
        .unwrap_or(libc::EINVAL));
    }
    let new_flags = if blocking != 0 {
      flags & !libc::O_NONBLOCK
    } else {
      flags | libc::O_NONBLOCK
    };
    if new_flags != flags && libc::fcntl(fd, libc::F_SETFL, new_flags) == -1 {
      return -(std::io::Error::last_os_error()
        .raw_os_error()
        .unwrap_or(libc::EINVAL));
    }
    0
  }
}

fn all_lint_rules_are_listed_in_schema_file() {
  let all_rules = get_all_rules();

  let rules_schema_path =
    util::root_path().join("cli/schemas/lint-rules.v1.json");
  let rules_schema_file =
    std::fs::read_to_string(&rules_schema_path).unwrap();

  let schema: RulesSchema = serde_json::from_str(&rules_schema_file).unwrap();

  const UPDATE_ENV_VAR_NAME: &str = "UPDATE_EXPECTED";

  let rules_list = schema.one_of.1.r#enum;

  if std::env::var(UPDATE_ENV_VAR_NAME).ok().is_none() {
    assert_eq!(
      rules_list, all_rules,
      "Lint rules schema file not up to date. Run again with {}=1 to update the expected output",
      UPDATE_ENV_VAR_NAME
    );
    return;
  }

  let new_schema = RulesSchema {
    schema: schema.schema,
    one_of: (schema.one_of.0, RulesEnum { r#enum: all_rules }),
  };

  std::fs::write(
    &rules_schema_path,
    format!("{}\n", serde_json::to_string_pretty(&new_schema).unwrap(),),
  )
  .unwrap();
}

async fn package_info(
  &self,
  name: &str,
) -> Result<Arc<NpmPackageInfo>, NpmRegistryPackageInfoLoadError> {
  if let Some(data) = self.data.borrow_mut().get(name).cloned() {
    return Ok(data);
  }
  let file_path = packument_cache_filepath(name);
  if let Ok(data) = std::fs::read_to_string(&file_path)
    && let Ok(data) = serde_json::from_str::<Arc<NpmPackageInfo>>(&data)
  {
    self
      .data
      .borrow_mut()
      .insert(name.to_string(), data.clone());
    return Ok(data);
  }
  let url = packument_url(name);
  eprintln!("Downloading {}", url);
  let resp = reqwest::get(&url).await.unwrap();
  if resp.status() == StatusCode::NOT_FOUND {
    return Err(NpmRegistryPackageInfoLoadError::PackageNotExists {
      package_name: name.to_string(),
    });
  }
  let text = resp.text().await.unwrap();
  std::fs::write(&file_path, &text).unwrap();
  let data = serde_json::from_str::<Arc<NpmPackageInfo>>(&text).unwrap();
  self
    .data
    .borrow_mut()
    .insert(name.to_string(), data.clone());
  Ok(data)
}

fn test_matmul() {
    // Verify that small matrix gets the right result.
    let a: Vec<f32> = vec![1.0, 2.0, 3.0, 4.0];
    let b: Vec<f32> = vec![5.0, 6.0, 7.0, 8.0];
    let mul: Vec<f32> = vec![19.0, 22.0, 43.0, 50.0];
    let mut dest = vec![0f32; 4];
    matmulz(&a[..], &b[..], &mut dest[..]);
    assert_eq!(mul, dest);

    seq_matmulz(&a[..], &b[..], &mut dest[..]);
    assert_eq!(mul, dest);

    matmul_strassen(&a[..], &b[..], &mut dest[..]);
    assert_eq!(mul, dest);

    // Verify that large matrix gets the same results in parallel and serial algorithms.
    let n = 1 << 14;
    assert!(n > MULT_CHUNK); // If we don't recurse we're not testing much.
    let a: Vec<f32> = (0..n).map(|i| (i % 101) as f32).collect();
    let b: Vec<f32> = (0..n).map(|i| (i % 101 + 7) as f32).collect();
    let mut seqmul = vec![0f32; n];
    seq_matmulz(&a[..], &b[..], &mut seqmul[..]);
    let mut rmul = vec![0f32; n];
    matmulz(&a[..], &b[..], &mut rmul[..]);
    assert_eq!(rmul, seqmul);

    // Verify strassen gets the same results.
    for d in rmul.iter_mut() {
        *d = 0.0;
    }
    matmul_strassen(&a[..], &b[..], &mut rmul[..]);
    assert_eq!(rmul, seqmul);
}

fn render_option(&self, params: &[&str], block: &str, man_name: &str) -> Result<String, Error> {
    let mut result = String::new();
    fn unwrap_p(t: &str) -> &str {
        unwrap(t, "<p>", "</p>")
    }

    for param in params {
        let rendered = self.render_html(param)?;
        let no_p = unwrap_p(&rendered);
        // split out first term to use as the id.
        let first = no_p
            .split_whitespace()
            .next()
            .ok_or_else(|| format_err!("did not expect option `{}` to be empty", param))?;
        let no_tags = trim_tags(first);
        if no_tags.is_empty() {
            bail!("unexpected empty option with no tags `{}`", param);
        }
        let id = format!("option-{}-{}", man_name, no_tags);
        write!(
            result,
            "<dt class=\"option-term\" id=\"{id}\">\
            <a class=\"option-anchor\" href=\"#{id}\">{no_p}</a></dt>\n",
        )?;
    }
    let rendered_block = self.render_html(block)?;
    write!(
        result,
        "<dd class=\"option-desc\">{rendered_block}</dd>\n\n",
    )?;
    Ok(result)
}

fn check_expr(&mut self, cx: &LateContext<'tcx>, expr: &Expr<'_>) {
    if expr.span.from_expansion() {
        return;
    }

    if let Some(OptionOrResultFn {
        kind,
        ref mut return_ty_span,
    }) = self.current_fn
        && let Some((oor, fn_name)) = is_unwrap_or_expect_call(cx, expr)
        && oor == kind
    {
        span_lint_and_then(
            cx,
            UNWRAP_IN_RESULT,
            expr.span,
            format!("`{fn_name}` used in a function that returns {}", kind.with_article()),
            |diag| {
                // Issue the note and help only once per function
                if let Some(span) = return_ty_span.take() {
                    diag.span_note(span, "in this function signature");
                    let complement = if kind == OptionOrResult::Result {
                        " or calling the `.map_err()` method"
                    } else {
                        ""
                    };
                    diag.help(format!("consider using the `?` operator{complement}"));
                }
            },
        );
    }
}

fn check_for_debugger_visualizer(&mut self, attrs: &[ast::Attribute]) {
    if let Some(Attribute::Parsed(AttributeKind::DebuggerVisualizer(visualizers))) =
        AttributeParser::parse_limited(&self.sess, attrs, &[sym::debugger_visualizer])
    {
        for DebugVisualizer { span, visualizer_type, path } in visualizers {
            let file = match resolve_path(&self.sess, path.as_str(), span) {
                Ok(file) => file,
                Err(err) => {
                    err.emit();
                    return;
                }
            };

            match self.sess.source_map().load_binary_file(&file) {
                Ok((source, _)) => {
                    self.visualizers.push(DebuggerVisualizerFile::new(
                        source,
                        visualizer_type,
                        file,
                    ));
                }
                Err(error) => {
                    self.sess.dcx().emit_err(DebugVisualizerUnreadable {
                        span,
                        file: &file,
                        error,
                    });
                }
            }
        }
    }
}

fn mode_and_needs_parens_for_adjustment_hints(
    expr: &ast::Expr,
    mode: AdjustmentHintsMode,
) -> (bool, bool, bool) {
    use {AdjustmentHintsMode::*, std::cmp::Ordering::*};

    match mode {
        Prefix | Postfix => {
            let postfix = matches!(mode, Postfix);
            let (inside, outside) = needs_parens_for_adjustment_hints(expr, postfix);
            (postfix, inside, outside)
        }
        PreferPrefix | PreferPostfix => {
            let prefer_postfix = matches!(mode, PreferPostfix);

            let (pre_inside, pre_outside) = needs_parens_for_adjustment_hints(expr, false);
            let prefix = (false, pre_inside, pre_outside);
            let pre_count = pre_inside as u8 + pre_outside as u8;

            let (post_inside, post_outside) = needs_parens_for_adjustment_hints(expr, true);
            let postfix = (true, post_inside, post_outside);
            let post_count = post_inside as u8 + post_outside as u8;

            match pre_count.cmp(&post_count) {
                Less => prefix,
                Greater => postfix,
                Equal if prefer_postfix => postfix,
                Equal => prefix,
            }
        }
    }
}

fn release_gcc(path: &std::path::Path) -> Result<Vec<u8>, String> {
    // Build a file named `gcc_elf`...
    let exe_path = path.with_extension("gcc_elf");
    // ... using the GCC backend ...
    let output = std::process::Command::new("./y.sh")
        .arg("rustc")
        .arg(path)
        .arg("-O")
        .arg("-o")
        .arg(&exe_path)
        .output()
        .map_err(|err| format!("{err:?}"))?;
    // ... check that the compilation succeeded ...
    if !output.status.success() {
        return Err(format!("GCC compilation failed:{output:?}"));
    }
    // ... run the resulting executable ..
    let output =
        std::process::Command::new(&exe_path).output().map_err(|err| format!("{err:?}"))?;
    // ... check it run normally ...
    if !output.status.success() {
        return Err(format!(
            "The program at {path:?}, compiled with GCC, exited unsuccessfully:{output:?}"
        ));
    }
    // ... cleanup that executable ...
    std::fs::remove_file(exe_path).map_err(|err| format!("{err:?}"))?;
    // ... and return the output(stdout + stderr - this allows UB checks to fire).
    let mut res = output.stdout;
    res.extend(output.stderr);
    Ok(res)
}

fn check_item(&mut self, cx: &LateContext<'_>, item: &Item<'_>) {
    let (lint, msg, fields) = match item.kind {
        ItemKind::Enum(..) => (
            EXHAUSTIVE_ENUMS,
            "exported enums should not be exhaustive",
            [].as_slice(),
        ),
        ItemKind::Struct(_, _, v) if v.fields().iter().all(|f| f.default.is_none()) => (
            EXHAUSTIVE_STRUCTS,
            "exported structs should not be exhaustive",
            v.fields(),
        ),
        _ => return,
    };
    if cx.effective_visibilities.is_exported(item.owner_id.def_id)
        && let attrs = cx.tcx.hir_attrs(item.hir_id())
        && !find_attr!(attrs, NonExhaustive(..))
        && fields.iter().all(|f| cx.tcx.visibility(f.def_id).is_public())
    {
        span_lint_and_then(cx, lint, item.span, msg, |diag| {
            let suggestion_span = item.span.shrink_to_lo();
            let indent = " ".repeat(indent_of(cx, item.span).unwrap_or(0));
            let sugg = format!("#[non_exhaustive]\n{indent}");
            diag.span_suggestion_verbose(
                suggestion_span,
                "try adding #[non_exhaustive]",
                sugg,
                Applicability::MaybeIncorrect,
            );
        });
    }
}
